import json
import re

with open(locals()['var_function-call-2311230859303334761'], 'r') as f:
    books = json.load(f)
with open(locals()['var_function-call-2311230859303334210'], 'r') as f:
    reviews = json.load(f)

# Parse years
book_years = {}
year_pattern = re.compile(r'\b(19\d{2}|20\d{2})\b')

for b in books:
    bid_str = b['book_id']
    try:
        bid = int(bid_str.split('_')[-1])
    except:
        continue
    details = b['details']
    matches = year_pattern.findall(details)
    if matches:
        book_years[bid] = int(matches[0]) 

print(f"Book years keys count: {len(book_years)}")
print(f"Sample book years: {list(book_years.items())[:5]}")

# Aggregate
decade_stats = {} 
count = 0

for r in reviews:
    pid_str = r['purchase_id']
    try:
        pid = int(pid_str.split('_')[-1])
    except:
        continue

    if pid in book_years:
        year = book_years[pid]
        decade = (year // 10) * 10
        decade_key = f"{decade}s"

        try:
            rating = float(r['rating'])
        except:
            continue

        if decade_key not in decade_stats:
            decade_stats[decade_key] = {'ratings': [], 'books': set()}

        decade_stats[decade_key]['ratings'].append(rating)
        decade_stats[decade_key]['books'].add(pid)

        if count < 10:
            print(f"Matched PID {pid} Year {year} Decade {decade_key}")
            count += 1

print(f"Total reviews processed: {len(reviews)}")
print(f"Stats keys: {list(decade_stats.keys())}")
for k, v in decade_stats.items():
    print(f"Decade {k}: {len(v['books'])} distinct books")

print("__RESULT__:")
print(json.dumps("debug4 done"))

